-- Main access control logic
function access_control()
    -- Check for specific endpoints where permissions are skipped
    if ngx.var.uri == "/admin" or ngx.var.uri == "/api" then
        return
    end

    -- Extract token from headers
    local token = ngx.req.get_headers()["Authorization"]
    if not token then
        ngx.status = ngx.HTTP_UNAUTHORIZED
        ngx.say("Unauthorized: No token provided")
        return ngx.exit(ngx.HTTP_UNAUTHORIZED)
    end

    -- Remove the "Bearer " prefix from the token
    token = string.sub(token, 8)

    -- Validate the token
    local payload = validate_token(token)
    if not payload then
        ngx.status = ngx.HTTP_FORBIDDEN
        ngx.say("Forbidden: Invalid token")
        return ngx.exit(ngx.HTTP_FORBIDDEN)
    end

    -- Extract user role from the token payload
    local user_role = payload.role
    if not user_role then
        ngx.status = ngx.HTTP_FORBIDDEN
        ngx.say("Forbidden: No role information in token")
        return ngx.exit(ngx.HTTP_FORBIDDEN)
    end

    -- Define required roles for specific endpoints or operations
    local required_roles = {
        ["/dashboard"] = "user",
        ["/settings"] = "admin"
    }

    -- Check if the user has the required role
    local required_role = required_roles[ngx.var.uri]
    if required_role and user_role ~= required_role then
        ngx.status = ngx.HTTP_FORBIDDEN
        ngx.say("Forbidden: Insufficient permissions")
        return ngx.exit(ngx.HTTP_FORBIDDEN)
    end

    -- If all checks pass, allow access
end

-- Call the access control function
access_control()